"use strict";(globalThis.webpackChunklearncpp_docs=globalThis.webpackChunklearncpp_docs||[]).push([[9675],{63254(n,r,t){t.r(r),t.d(r,{assets:()=>u,contentTitle:()=>d,default:()=>i,frontMatter:()=>s,metadata:()=>l,toc:()=>c});const l=JSON.parse('{"id":"cpp11/nullptr","title":"nullptr\u5173\u952e\u5b57","description":"C++11 nullptr\u5173\u952e\u5b57 \u6559\u5b66\u793a\u4f8b","source":"@site/docs/cpp11/04-nullptr.md","sourceDirName":"cpp11","slug":"/cpp11/04-nullptr","permalink":"/LearnModernCpp/docs/cpp11/04-nullptr","draft":false,"unlisted":false,"tags":[{"inline":true,"label":"cpp11","permalink":"/LearnModernCpp/docs/tags/cpp-11"},{"inline":true,"label":"nullptr","permalink":"/LearnModernCpp/docs/tags/nullptr"}],"version":"current","sidebarPosition":5,"frontMatter":{"sidebar_position":5,"slug":"04-nullptr","title":"nullptr\u5173\u952e\u5b57","description":"C++11 nullptr\u5173\u952e\u5b57 \u6559\u5b66\u793a\u4f8b","tags":["cpp11","nullptr"]},"sidebar":"docs","previous":{"title":"Lambda\u8868\u8fbe\u5f0f","permalink":"/LearnModernCpp/docs/cpp11/03-lambda-expressions"},"next":{"title":"\u5f3a\u7c7b\u578b\u679a\u4e3e (enum class / scoped enum)","permalink":"/LearnModernCpp/docs/cpp11/05-enum-class"}}');var e=t(74848),p=t(28453);const s={sidebar_position:5,slug:"04-nullptr",title:"nullptr\u5173\u952e\u5b57",description:"C++11 nullptr\u5173\u952e\u5b57 \u6559\u5b66\u793a\u4f8b",tags:["cpp11","nullptr"]},d="nullptr\u5173\u952e\u5b57",u={},c=[{value:"\u5b8c\u6574\u6e90\u7801",id:"\u5b8c\u6574\u6e90\u7801",level:2},{value:"\u53c2\u8003\u94fe\u63a5",id:"\u53c2\u8003\u94fe\u63a5",level:2}];function o(n){const r={a:"a",code:"code",h1:"h1",h2:"h2",header:"header",li:"li",p:"p",pre:"pre",ul:"ul",...(0,p.R)(),...n.components};return(0,e.jsxs)(e.Fragment,{children:[(0,e.jsx)(r.header,{children:(0,e.jsx)(r.h1,{id:"nullptr\u5173\u952e\u5b57",children:"nullptr\u5173\u952e\u5b57"})}),"\n",(0,e.jsx)(r.p,{children:"C++11 \u6807\u51c6\u5f15\u5165\u7684 nullptr\u5173\u952e\u5b57 \u7279\u6027\u5b8c\u6574\u6559\u5b66\u793a\u4f8b\u3002"}),"\n",(0,e.jsx)(r.h2,{id:"\u5b8c\u6574\u6e90\u7801",children:"\u5b8c\u6574\u6e90\u7801"}),"\n",(0,e.jsx)(r.pre,{children:(0,e.jsx)(r.code,{className:"language-cpp",metastring:'title="cpp11/04_nullptr.cpp"',children:'/**\r\n * ============================================================\r\n * \u7279\u6027\u540d\u79f0: nullptr\u5173\u952e\u5b57\r\n * \u6240\u5c5e\u6807\u51c6: C++11\r\n * ============================================================\r\n *\r\n * [\u662f\u4ec0\u4e48]: nullptr\u662fC++11\u5f15\u5165\u7684\u7a7a\u6307\u9488\u5b57\u9762\u91cf\uff0c\u7c7b\u578b\u4e3astd::nullptr_t\uff0c\r\n *          \u4e13\u95e8\u7528\u4e8e\u8868\u793a\u7a7a\u6307\u9488\u3002\r\n *\r\n * [\u4e3a\u4ec0\u4e48\u5f15\u5165]: C++03\u4e2d\u4f7f\u7528NULL\uff08\u88ab\u5b9a\u4e49\u4e3a0\u6216(void*)0\uff09\u6216\u5b57\u9762\u91cf0\u8868\u793a\r\n *   \u7a7a\u6307\u9488\uff0c\u4f46\u5b83\u4eec\u672c\u8d28\u4e0a\u662f\u6574\u6570\uff0c\u5728\u51fd\u6570\u91cd\u8f7d\u51b3\u8bae\u65f6\u4f1a\u4ea7\u751f\u6b67\u4e49\u3002nullptr\r\n *   \u89e3\u51b3\u4e86\u8fd9\u4e00\u6839\u672c\u6027\u7f3a\u9677\u3002\r\n *\r\n * [\u5173\u952e\u8981\u70b9]:\r\n *   - nullptr\u7684\u7c7b\u578b\u662fstd::nullptr_t\uff0c\u53ef\u9690\u5f0f\u8f6c\u6362\u4e3a\u4efb\u4f55\u6307\u9488\u7c7b\u578b\r\n *   - nullptr\u4e0d\u80fd\u9690\u5f0f\u8f6c\u6362\u4e3a\u6574\u6570\u7c7b\u578b\r\n *   - \u5728\u51fd\u6570\u91cd\u8f7d\u4e2d\uff0cnullptr\u660e\u786e\u5339\u914d\u6307\u9488\u53c2\u6570\r\n *   - \u6a21\u677f\u4e2d\u4f20\u9012nullptr\u80fd\u6b63\u786e\u63a8\u5bfc\u4e3a\u6307\u9488\u7c7b\u578b\u76f8\u5173\u7684\u53c2\u6570\r\n * ============================================================\r\n */\r\n\r\n#include <iostream>\r\n#include <cstddef> // std::nullptr_t\r\n#include <string>\r\n#include <memory>\r\n\r\n// ============================================================\r\n// \u8f85\u52a9\uff1a\u7528\u4e8e\u6f14\u793a\u91cd\u8f7d\u51b3\u8bae\u7684\u51fd\u6570\r\n// ============================================================\r\nvoid process(int value) {\r\n    std::cout << "  \u8c03\u7528\u4e86 process(int): " << value << std::endl;\r\n}\r\n\r\nvoid process(int* ptr) {\r\n    std::cout << "  \u8c03\u7528\u4e86 process(int*): "\r\n              << (ptr ? "\u975e\u7a7a\u6307\u9488" : "\u7a7a\u6307\u9488") << std::endl;\r\n}\r\n\r\n// ============================================================\r\n// \u8f85\u52a9\uff1a\u6a21\u677f\u51fd\u6570\uff0c\u7528\u4e8e\u6f14\u793anullptr\u5728\u6a21\u677f\u4e2d\u7684\u884c\u4e3a\r\n// ============================================================\r\ntemplate <typename T>\r\nvoid check_null(T ptr) {\r\n    if (ptr == nullptr) {\r\n        std::cout << "  \u6307\u9488\u4e3a\u7a7a" << std::endl;\r\n    } else {\r\n        std::cout << "  \u6307\u9488\u975e\u7a7a" << std::endl;\r\n    }\r\n}\r\n\r\ntemplate <typename T>\r\nvoid show_type(T) {\r\n    std::cout << "  \u6a21\u677f\u53c2\u6570\u7c7b\u578b: " << typeid(T).name() << std::endl;\r\n}\r\n\r\n// ============================================================\r\n// \u57fa\u7840\u7528\u6cd5\r\n// ============================================================\r\nvoid basic_usage() {\r\n    std::cout << "===== \u57fa\u7840\u7528\u6cd5 =====" << std::endl;\r\n\r\n    // 1. nullptr\u521d\u59cb\u5316\u6307\u9488\r\n    int* p1 = nullptr;\r\n    double* p2 = nullptr;\r\n    std::string* p3 = nullptr;\r\n\r\n    std::cout << "p1\u662f\u5426\u4e3a\u7a7a: " << (p1 == nullptr ? "\u662f" : "\u5426") << std::endl;\r\n    std::cout << "p2\u662f\u5426\u4e3a\u7a7a: " << (p2 == nullptr ? "\u662f" : "\u5426") << std::endl;\r\n\r\n    // 2. \u4e0eNULL/0\u7684\u5bf9\u6bd4\r\n    // NULL\u5728C++\u4e2d\u901a\u5e38\u88ab\u5b9a\u4e49\u4e3a0\uff08\u6574\u6570\u96f6\uff09\r\n    // nullptr\u5219\u662f\u4e00\u4e2a\u660e\u786e\u7684\u7a7a\u6307\u9488\u5b57\u9762\u91cf\r\n    int* p4 = nullptr;   // \u63a8\u8350: \u610f\u56fe\u660e\u786e\r\n    int* p5 = NULL;      // C++03\u98ce\u683c: \u672c\u8d28\u662f0\r\n    int* p6 = 0;         // C\u98ce\u683c: \u5bb9\u6613\u4e0e\u6574\u65700\u6df7\u6dc6\r\n\r\n    std::cout << "\u4e09\u79cd\u65b9\u5f0f\u90fd\u662f\u7a7a\u6307\u9488: "\r\n              << (p4 == nullptr && p5 == nullptr && p6 == nullptr ? "\u662f" : "\u5426")\r\n              << std::endl;\r\n\r\n    // 3. nullptr\u5728\u6761\u4ef6\u5224\u65ad\u4e2d\r\n    int value = 42;\r\n    int* ptr = &value;\r\n    if (ptr) {  // \u975e\u7a7a\u6307\u9488\u5728\u5e03\u5c14\u4e0a\u4e0b\u6587\u4e2d\u4e3atrue\r\n        std::cout << "ptr\u6307\u5411: " << *ptr << std::endl;\r\n    }\r\n    ptr = nullptr;\r\n    if (!ptr) { // nullptr\u5728\u5e03\u5c14\u4e0a\u4e0b\u6587\u4e2d\u4e3afalse\r\n        std::cout << "ptr\u73b0\u5728\u4e3a\u7a7a" << std::endl;\r\n    }\r\n}\r\n\r\n// ============================================================\r\n// \u8fdb\u9636\u7528\u6cd5\r\n// ============================================================\r\nvoid advanced_usage() {\r\n    std::cout << "\\n===== \u8fdb\u9636\u7528\u6cd5 =====" << std::endl;\r\n\r\n    // 1. \u91cd\u8f7d\u51b3\u8bae \u2014\u2014 nullptr\u7684\u6838\u5fc3\u4f18\u52bf\r\n    std::cout << "\u4f7f\u7528nullptr\u8c03\u7528\u91cd\u8f7d\u51fd\u6570:" << std::endl;\r\n\r\n    // process(NULL);      // \u6b67\u4e49! NULL\u662f0\uff0c\u53ef\u80fd\u5339\u914dint\u6216int*\r\n    process(nullptr);      // \u660e\u786e\u5339\u914d process(int*)\r\n    process(42);           // \u660e\u786e\u5339\u914d process(int)\r\n\r\n    // 2. \u6a21\u677f\u4e2d\u4f7f\u7528nullptr\r\n    std::cout << "\\n\u6a21\u677f\u4e2d\u4f7f\u7528nullptr:" << std::endl;\r\n    int x = 10;\r\n    check_null(&x);       // \u975e\u7a7a\r\n    check_null(nullptr);  // \u7a7a\r\n\r\n    // \u67e5\u770bnullptr\u7684\u6a21\u677f\u53c2\u6570\u63a8\u5bfc\r\n    show_type(nullptr);   // T\u63a8\u5bfc\u4e3astd::nullptr_t\r\n    show_type((int*)nullptr); // T\u63a8\u5bfc\u4e3aint*\r\n\r\n    // 3. nullptr_t\u7c7b\u578b\r\n    std::cout << "\\nnullptr_t\u7c7b\u578b\u7684\u4f7f\u7528:" << std::endl;\r\n    std::nullptr_t null_val = nullptr; // \u53ef\u4ee5\u58f0\u660enullptr_t\u53d8\u91cf\r\n    int* p = null_val;   // nullptr_t\u53ef\u9690\u5f0f\u8f6c\u6362\u4e3a\u4efb\u4f55\u6307\u9488\u7c7b\u578b\r\n    std::cout << "nullptr_t\u53d8\u91cf\u8d4b\u7ed9int*: " << (p == nullptr ? "\u6210\u529f" : "\u5931\u8d25") << std::endl;\r\n\r\n    // 4. \u4e0e\u667a\u80fd\u6307\u9488\u914d\u5408\r\n    std::shared_ptr<int> sp1 = nullptr;  // \u7a7a\u7684shared_ptr\r\n    std::unique_ptr<int> up1 = nullptr;  // \u7a7a\u7684unique_ptr\r\n    std::cout << "\u7a7ashared_ptr: " << (sp1 == nullptr ? "\u662f" : "\u5426") << std::endl;\r\n\r\n    sp1 = std::make_shared<int>(100);\r\n    if (sp1 != nullptr) {\r\n        std::cout << "shared_ptr\u6307\u5411: " << *sp1 << std::endl;\r\n    }\r\n    sp1 = nullptr; // \u91cd\u7f6e\u4e3a\u7a7a\uff08\u91ca\u653e\u8d44\u6e90\uff09\r\n    std::cout << "\u91cd\u7f6e\u540e: " << (sp1 == nullptr ? "\u5df2\u91ca\u653e" : "\u4ecd\u6709\u6548") << std::endl;\r\n}\r\n\r\n// ============================================================\r\n// \u6613\u9519\u70b9\u4e0e\u9677\u9631\r\n// ============================================================\r\nvoid pitfalls() {\r\n    std::cout << "\\n===== \u6613\u9519\u70b9\u4e0e\u9677\u9631 =====" << std::endl;\r\n\r\n    // \u9677\u96311: NULL\u5728\u91cd\u8f7d\u4e2d\u53ef\u80fd\u5339\u914dint\u800c\u975e\u6307\u9488\r\n    std::cout << "\u4f7f\u75280\u8c03\u7528:" << std::endl;\r\n    process(0);           // \u5339\u914d process(int), \u4e0d\u662f\u6307\u9488\u7248\u672c!\r\n    std::cout << "\u4f7f\u7528nullptr\u8c03\u7528:" << std::endl;\r\n    process(nullptr);     // \u6b63\u786e\u5339\u914d process(int*)\r\n\r\n    // \u9677\u96312: nullptr\u4e0d\u80fd\u7528\u4e8e\u7b97\u672f\u8fd0\u7b97\r\n    // int n = nullptr;         // \u7f16\u8bd1\u9519\u8bef! nullptr\u4e0d\u80fd\u8f6c\u6362\u4e3aint\r\n    // int m = nullptr + 1;     // \u7f16\u8bd1\u9519\u8bef!\r\n    std::cout << "\\nnullptr\u4e0d\u80fd\u53c2\u4e0e\u7b97\u672f\u8fd0\u7b97\uff08\u7f16\u8bd1\u671f\u4fdd\u8bc1\u5b89\u5168\uff09" << std::endl;\r\n\r\n    // \u9677\u96313: nullptr\u4e0e\u5e03\u5c14\u503c\r\n    // bool b = nullptr; // \u67d0\u4e9b\u7f16\u8bd1\u5668\u5141\u8bb8\u4f46\u4f1a\u6709\u8b66\u544a\r\n    // \u63a8\u8350\u4f7f\u7528 false \u800c\u975e nullptr \u6765\u8868\u793a\u5e03\u5c14\u5047\u503c\r\n    std::cout << "\u4e0d\u8981\u7528nullptr\u4ee3\u66fffalse\uff0c\u867d\u7136\u5728\u5e03\u5c14\u4e0a\u4e0b\u6587\u4e2d\u5b83\u7b49\u4ef7\u4e8efalse" << std::endl;\r\n\r\n    // \u9677\u96314: \u4ecd\u9700\u6ce8\u610f\u7a7a\u6307\u9488\u89e3\u5f15\u7528\r\n    int* dangerous = nullptr;\r\n    // *dangerous = 42; // \u8fd0\u884c\u65f6\u5d29\u6e83! nullptr\u53ea\u9632\u6b62\u7c7b\u578b\u6b67\u4e49\uff0c\u4e0d\u9632\u6b62\u89e3\u5f15\u7528\r\n    std::cout << "nullptr\u4e0d\u80fd\u9632\u6b62\u7a7a\u6307\u9488\u89e3\u5f15\u7528\uff0c\u4ecd\u9700\u68c0\u67e5!" << std::endl;\r\n\r\n    // \u6700\u4f73\u5b9e\u8df5\u603b\u7ed3\r\n    std::cout << "\\n\u6700\u4f73\u5b9e\u8df5:" << std::endl;\r\n    std::cout << "  1. \u59cb\u7ec8\u7528nullptr\u66ff\u4ee3NULL\u548c0" << std::endl;\r\n    std::cout << "  2. \u4f7f\u7528\u524d\u68c0\u67e5\u6307\u9488\u662f\u5426\u4e3anullptr" << std::endl;\r\n    std::cout << "  3. \u4f18\u5148\u4f7f\u7528\u667a\u80fd\u6307\u9488\u800c\u975e\u88f8\u6307\u9488" << std::endl;\r\n}\r\n\r\n// ============================================================\r\n// \u4e3b\u51fd\u6570\r\n// ============================================================\r\nint main() {\r\n    std::cout << "========================================" << std::endl;\r\n    std::cout << "  C++11 \u7279\u6027: nullptr\u5173\u952e\u5b57" << std::endl;\r\n    std::cout << "========================================" << std::endl;\r\n\r\n    basic_usage();\r\n    advanced_usage();\r\n    pitfalls();\r\n\r\n    return 0;\r\n}\n'})}),"\n",(0,e.jsx)(r.h2,{id:"\u53c2\u8003\u94fe\u63a5",children:"\u53c2\u8003\u94fe\u63a5"}),"\n",(0,e.jsxs)(r.ul,{children:["\n",(0,e.jsx)(r.li,{children:(0,e.jsx)(r.a,{href:"https://en.cppreference.com/w/cpp/language/nullptr",children:"cppreference: nullptr\u5173\u952e\u5b57"})}),"\n"]})]})}function i(n={}){const{wrapper:r}={...(0,p.R)(),...n.components};return r?(0,e.jsx)(r,{...n,children:(0,e.jsx)(o,{...n})}):o(n)}},28453(n,r,t){t.d(r,{R:()=>s,x:()=>d});var l=t(96540);const e={},p=l.createContext(e);function s(n){const r=l.useContext(p);return l.useMemo(function(){return"function"==typeof n?n(r):{...r,...n}},[r,n])}function d(n){let r;return r=n.disableParentContext?"function"==typeof n.components?n.components(e):n.components||e:s(n.components),l.createElement(p.Provider,{value:r},n.children)}}}]);